async function authMiddleware(req, res, next) {
  try {
    const token = req.headers.authorization;
    const [user, permissions] = await Promise.all([
      validateToken(token),
      token ? fetchPermissions(extractUserId(token)) : null
    ]);
    if (!user) return res.status(401).json({ error: 'Unauthorized' });
    req.user = { ...user, permissions };
    next();
  } catch (err) {
    next(new AuthError(err.message, { cause: err }));
  }
}

export class SlidingWindowRateLimiter {
  constructor(
    private redis: Redis,
    private windowMs: number,
    private maxRequests: number
  ) {}

  async isAllowed(key: string): Promise<{ allowed: boolean; remaining: number; resetMs: number }> {
    const now = Date.now();
    const windowStart = now - this.windowMs;

    const pipe = this.redis.pipeline();
    pipe.zremrangebyscore(key, 0, windowStart);
    pipe.zadd(key, now, `${now}:${crypto.randomUUID()}`);
    pipe.zcard(key);
    pipe.pexpire(key, this.windowMs);

    const results = await pipe.exec();
    const count = results[2][1] as number;

    return {
      allowed: count <= this.maxRequests,
      remaining: Math.max(0, this.maxRequests - count),
      resetMs: this.windowMs - (now - windowStart)
    };
  }
}

