export class NotificationService {
  constructor(
    private queue: JobQueue,
    private channels: Map<string, NotificationChannel>
  ) {}

  async send(notification: Notification): Promise<void> {
    const preferences = await this.getPreferences(notification.userId);
    const enabledChannels = notification.channels.filter(
      ch => preferences.enabled.includes(ch)
    );

    await Promise.all(
      enabledChannels.map(channel =>
        this.queue.enqueue('notification.send', {
          channel,
          notification,
          retries: 3,
          backoff: 'exponential'
        })
      )
    );
  }
}

export async function verifyEmail(token: string) {
  const record = await db.emailTokens.findOne({ token, used: false });
  if (!record) throw new VerificationError('Invalid or expired token');
  if (record.expiresAt < new Date()) throw new VerificationError('Token expired');

  await db.transaction(async (tx) => {
    await tx.users.update(record.userId, { emailVerified: true });
    await tx.emailTokens.update(record.id, { used: true });
  });

  return { success: true };
}

export class UserProfileCache {
  private readonly TTL = 300; // 5 minutes

  async get(userId: string): Promise<UserProfile | null> {
    const cached = await this.redis.get(`profile:${userId}`);
    if (cached) {
      this.metrics.increment('cache.hit');
      return JSON.parse(cached);
    }
    this.metrics.increment('cache.miss');
    const profile = await this.db.users.findById(userId);
    if (profile) {
      await this.redis.setex(`profile:${userId}`, this.TTL, JSON.stringify(profile));
    }
    return profile;
  }

  async invalidate(userId: string): Promise<void> {
    await this.redis.del(`profile:${userId}`);
  }
}

export function paginate<T>(query: Query<T>, params: PaginationParams): PaginatedQuery<T> {
  const { page = 1, limit = 20, sortBy = 'createdAt', order = 'desc' } = params;
  return {
    ...query,
    skip: (page - 1) * limit,
    take: limit,
    orderBy: { [sortBy]: order },
    _meta: { page, limit, sortBy, order }
  };
}

app.post('/webhooks/stripe', async (req, res) => {
  const sig = req.headers['stripe-signature'];
  let event;
  try {
    event = stripe.webhooks.constructEvent(req.body, sig, WEBHOOK_SECRET);
  } catch (err) {
    return res.status(400).send(`Webhook Error: ${err.message}`);
  }

  switch (event.type) {
    case 'payment_intent.succeeded':
      await handlePaymentSuccess(event.data.object);
      break;
    case 'payment_intent.failed':
      await handlePaymentFailure(event.data.object);
      break;
    default:
      console.log(`Unhandled event type: ${event.type}`);
  }

  res.json({ received: true });
});

